import { useState } from "react";
import part6Questions from "./questions/part6";
import part7Questions from "./questions/part7";
import prepositions from "./questions/part5/grammar_prepositions";
import tense from "./questions/part5/grammar_tense";
import partOfSpeech from "./questions/part5/grammar_partofspeech";
import conjunctions from "./questions/part5/grammar_conjunctions";
import verbForms from "./questions/part5/grammar_verbforms";
import relatives from "./questions/part5/grammar_relatives";
import comparison from "./questions/part5/grammar_comparison";
import passive from "./questions/part5/grammar_passive";
import subjunctive from "./questions/part5/grammar_subjunctive";
import vocabulary from "./questions/part5/grammar_vocabulary";

const grammarTopics = [
  { key: "prepositions", label: "前置詞", data: prepositions },
  { key: "tense", label: "時制", data: tense },
  { key: "partOfSpeech", label: "品詞", data: partOfSpeech },
  { key: "conjunctions", label: "接続詞", data: conjunctions },
  { key: "verbForms", label: "動詞の形", data: verbForms },
  { key: "relatives", label: "関係詞", data: relatives },
  { key: "comparison", label: "比較", data: comparison },
  { key: "passive", label: "受動態", data: passive },
  { key: "subjunctive", label: "仮定法", data: subjunctive },
  { key: "vocabulary", label: "語彙・コロケーション", data: vocabulary },
];

const levelInfo = {
  beginner: { label: "初級", color: "#1D9E75", bg: "#E1F5EE", desc: "目標スコア: 〜500" },
  intermediate: { label: "中級", color: "#378ADD", bg: "#E6F1FB", desc: "目標スコア: 500〜700" },
  advanced: { label: "上級", color: "#534AB7", bg: "#EEEDFE", desc: "目標スコア: 700〜" },
};

function App() {
  const [part, setPart] = useState(null);
  const [topic, setTopic] = useState(null);
  const [level, setLevel] = useState(null);
  const [current, setCurrent] = useState(0);
  const [currentQ, setCurrentQ] = useState(0);
  const [selected, setSelected] = useState(null);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);

  const handleReset = () => {
    setPart(null); setTopic(null); setLevel(null);
    setCurrent(0); setCurrentQ(0);
    setSelected(null); setScore(0); setFinished(false);
  };

  const handleBackToLevel = () => {
    setLevel(null); setCurrent(0);
    setSelected(null); setScore(0); setFinished(false);
  };

  const handleBackToTopic = () => {
    setTopic(null); setLevel(null); setCurrent(0);
    setSelected(null); setScore(0); setFinished(false);
  };

  // ===== パート選択画面 =====
  if (!part) {
    return (
      <div style={{ maxWidth: 500, margin: "60px auto", fontFamily: "sans-serif", padding: "0 20px" }}>
        <h1 style={{ textAlign: "center", marginBottom: 8 }}>TOEIC練習アプリ</h1>
        <p style={{ textAlign: "center", color: "#888", marginBottom: 40 }}>パートを選んでスタート</p>
        {[
          { key: "part5", label: "Part 5", desc: "短文穴埋め・文法項目別", color: "#1D9E75", bg: "#E1F5EE" },
          { key: "part6", label: "Part 6", desc: "長文穴埋め問題・文脈を読む力", color: "#378ADD", bg: "#E6F1FB" },
          { key: "part7", label: "Part 7", desc: "長文読解問題・内容理解", color: "#534AB7", bg: "#EEEDFE" },
        ].map((p) => (
          <button key={p.key} onClick={() => setPart(p.key)}
            style={{ display: "block", width: "100%", padding: "20px", margin: "12px 0", borderRadius: 12, border: "2px solid " + p.color, background: p.bg, cursor: "pointer", textAlign: "left" }}>
            <div style={{ fontSize: 20, fontWeight: "bold", color: p.color }}>{p.label}</div>
            <div style={{ fontSize: 14, color: "#555", marginTop: 4 }}>{p.desc}</div>
          </button>
        ))}
      </div>
    );
  }

  // ===== Part5：文法項目選択画面 =====
  if (part === "part5" && !topic) {
    return (
      <div style={{ maxWidth: 500, margin: "40px auto", fontFamily: "sans-serif", padding: "0 20px" }}>
        <h1 style={{ textAlign: "center", marginBottom: 8 }}>Part 5</h1>
        <p style={{ textAlign: "center", color: "#888", marginBottom: 32 }}>文法項目を選んでください</p>
        {grammarTopics.map((t) => (
          <button key={t.key} onClick={() => setTopic(t)}
            style={{ display: "block", width: "100%", padding: "16px 20px", margin: "8px 0", borderRadius: 10, border: "1px solid #ddd", background: "#fff", cursor: "pointer", textAlign: "left", fontSize: 16 }}>
            {t.label}
          </button>
        ))}
        <button onClick={handleReset} style={{ marginTop: 16, background: "none", border: "none", color: "#888", cursor: "pointer", fontSize: 14 }}>← パート選択に戻る</button>
      </div>
    );
  }

  // ===== Part5：レベル選択画面 =====
  if (part === "part5" && topic && !level) {
    return (
      <div style={{ maxWidth: 500, margin: "40px auto", fontFamily: "sans-serif", padding: "0 20px" }}>
        <h1 style={{ textAlign: "center", marginBottom: 4 }}>Part 5 ― {topic.label}</h1>
        <p style={{ textAlign: "center", color: "#888", marginBottom: 32 }}>難易度を選んでください（各20問）</p>
        {Object.entries(levelInfo).map(([key, val]) => (
          <button key={key} onClick={() => setLevel(key)}
            style={{ display: "block", width: "100%", padding: "20px", margin: "12px 0", borderRadius: 12, border: "2px solid " + val.color, background: val.bg, cursor: "pointer", textAlign: "left" }}>
            <div style={{ fontSize: 20, fontWeight: "bold", color: val.color }}>{val.label}</div>
            <div style={{ fontSize: 14, color: "#555", marginTop: 4 }}>{val.desc} ／ 20問</div>
          </button>
        ))}
        <button onClick={handleBackToTopic} style={{ marginTop: 16, background: "none", border: "none", color: "#888", cursor: "pointer", fontSize: 14 }}>← 文法項目選択に戻る</button>
      </div>
    );
  }

  // ===== Part5：問題画面 =====
  if (part === "part5" && topic && level) {
    const questions = topic.data[level];
    const q = questions[current];
    const info = levelInfo[level];

    if (finished) {
      return (
        <div style={{ maxWidth: 500, margin: "60px auto", fontFamily: "sans-serif", padding: "0 20px", textAlign: "center" }}>
          <h1>結果発表</h1>
          <p style={{ fontSize: 15, color: "#888", marginTop: 8 }}>Part5 ― {topic.label} ／ {info.label}編</p>
          <p style={{ fontSize: 48, fontWeight: "bold", color: info.color, margin: "24px 0" }}>{score} / {questions.length}</p>
          <p style={{ fontSize: 16, color: "#555", marginBottom: 32 }}>
            {score === questions.length ? "満点！素晴らしい！🎉" : score >= questions.length * 0.8 ? "よくできました！💪" : score >= questions.length * 0.6 ? "もう少し！頑張ろう！📚" : "復習が必要です！🔍"}
          </p>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <button onClick={handleBackToLevel} style={{ padding: "12px 32px", fontSize: 15, cursor: "pointer", borderRadius: 8, background: info.color, color: "white", border: "none" }}>同じ項目で別の難易度</button>
            <button onClick={handleBackToTopic} style={{ padding: "12px 32px", fontSize: 15, cursor: "pointer", borderRadius: 8, background: "#f0f0f0", color: "#333", border: "none" }}>別の文法項目へ</button>
            <button onClick={handleReset} style={{ padding: "12px 32px", fontSize: 15, cursor: "pointer", borderRadius: 8, background: "#f0f0f0", color: "#333", border: "none" }}>トップに戻る</button>
          </div>
        </div>
      );
    }

    return (
      <div style={{ maxWidth: 500, margin: "40px auto", fontFamily: "sans-serif", padding: "0 20px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <span style={{ background: info.bg, color: info.color, padding: "4px 12px", borderRadius: 20, fontSize: 12, fontWeight: "bold" }}>{topic.label} ／ {info.label}</span>
          <span style={{ color: "#888", fontSize: 14 }}>{current + 1} / {questions.length}</span>
        </div>
        <p style={{ fontSize: 18, lineHeight: 1.8, marginBottom: 24 }}>{q.question}</p>
        {q.choices.map((c, i) => (
          <button key={i} onClick={() => { if (selected) return; setSelected(c); if (c.startsWith(q.answer)) setScore(score + 1); }}
            style={{ display: "block", width: "100%", textAlign: "left", padding: "12px 16px", margin: "8px 0", fontSize: 15, cursor: selected ? "default" : "pointer", borderRadius: 8, border: "1px solid #ddd", background: selected ? (c.startsWith(q.answer) ? "#c8f7c5" : selected === c ? "#f7c5c5" : "#f9f9f9") : "#f9f9f9" }}>
            {c}
          </button>
        ))}
        {selected && (
          <div style={{ marginTop: 16, padding: 16, background: "#fffbe6", borderRadius: 8, lineHeight: 1.9, fontSize: 14, whiteSpace: "pre-line" }}>
            {q.explanation}
          </div>
        )}
        {selected && (
          <div style={{ marginTop: 8, display: "flex", flexDirection: "column", gap: 8 }}>
            <button onClick={() => { if (current + 1 >= questions.length) { setFinished(true); } else { setCurrent(current + 1); setSelected(null); } }}
              style={{ padding: "12px 32px", fontSize: 16, cursor: "pointer", borderRadius: 8, background: info.color, color: "white", border: "none" }}>
              {current + 1 >= questions.length ? "結果を見る" : "次の問題"}
            </button>
            <button onClick={handleReset} style={{ background: "none", border: "none", color: "#aaa", cursor: "pointer", fontSize: 13 }}>← トップに戻る</button>
          </div>
        )}
      </div>
    );
  }

  // ===== Part6・7共通：長文問題画面 =====
  const isP6 = part === "part6";
  const passages = isP6 ? part6Questions : part7Questions;
  const passage = passages[current];
  const q = passage.questions[currentQ];
  const partColor = isP6 ? "#378ADD" : "#534AB7";
  const partBg = isP6 ? "#E6F1FB" : "#EEEDFE";
  const totalQ = passages.reduce((a, p) => a + p.questions.length, 0);

  if (finished) {
    return (
      <div style={{ maxWidth: 500, margin: "60px auto", fontFamily: "sans-serif", padding: "0 20px", textAlign: "center" }}>
        <h1>結果発表</h1>
        <p style={{ fontSize: 16, color: "#888", marginTop: 8 }}>{isP6 ? "Part6" : "Part7"}</p>
        <p style={{ fontSize: 48, fontWeight: "bold", color: partColor, margin: "24px 0" }}>{score} / {totalQ}</p>
        <p style={{ fontSize: 16, color: "#555", marginBottom: 32 }}>
          {score === totalQ ? "満点！素晴らしい！🎉" : score >= totalQ * 0.8 ? "よくできました！💪" : score >= totalQ * 0.6 ? "もう少し！頑張ろう！📚" : "復習が必要です！🔍"}
        </p>
        <button onClick={handleReset} style={{ padding: "12px 32px", fontSize: 16, cursor: "pointer", borderRadius: 8, background: partColor, color: "white", border: "none" }}>トップに戻る</button>
      </div>
    );
  }

  const handleNextLong = () => {
    if (selected && selected.startsWith(q.answer)) setScore(score + 1);
    setSelected(null);
    if (currentQ + 1 < passage.questions.length) {
      setCurrentQ(currentQ + 1);
    } else if (current + 1 < passages.length) {
      setCurrent(current + 1);
      setCurrentQ(0);
    } else {
      setFinished(true);
    }
  };

  return (
    <div style={{ maxWidth: 600, margin: "40px auto", fontFamily: "sans-serif", padding: "0 20px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
        <span style={{ background: partBg, color: partColor, padding: "4px 12px", borderRadius: 20, fontSize: 13, fontWeight: "bold" }}>
          {isP6 ? "Part6" : "Part7"} ― 問題{current + 1}
        </span>
        <span style={{ color: "#888", fontSize: 14 }}>設問 {currentQ + 1} / {passage.questions.length}</span>
      </div>

      <div style={{ background: "#f9f9f9", borderRadius: 8, padding: 16, marginBottom: 24, fontSize: 14, lineHeight: 2 }}>
        <strong>{passage.title}</strong><br /><br />
        {passage.passage.map((line, i) => (
          <span key={i}>{line}<br /></span>
        ))}
      </div>

      <p style={{ fontSize: 16, fontWeight: "bold", marginBottom: 16 }}>{q.question}</p>

      {q.choices.map((c, i) => (
        <button key={i} onClick={() => { if (selected) return; setSelected(c); }}
          style={{ display: "block", width: "100%", textAlign: "left", padding: "12px 16px", margin: "8px 0", fontSize: 15, cursor: selected ? "default" : "pointer", borderRadius: 8, border: "1px solid #ddd", background: selected ? (c.startsWith(q.answer) ? "#c8f7c5" : selected === c ? "#f7c5c5" : "#f9f9f9") : "#f9f9f9" }}>
          {c}
        </button>
      ))}

      {selected && (
        <div style={{ marginTop: 16, padding: 16, background: "#fffbe6", borderRadius: 8, lineHeight: 1.8, fontSize: 14 }}>
          <strong>解説：</strong>{q.explanation}
        </div>
      )}

      {selected && (
        <div style={{ marginTop: 8, display: "flex", flexDirection: "column", gap: 8 }}>
          <button onClick={handleNextLong}
            style={{ padding: "12px 32px", fontSize: 16, cursor: "pointer", borderRadius: 8, background: partColor, color: "white", border: "none" }}>
            {currentQ + 1 >= passage.questions.length && current + 1 >= passages.length ? "結果を見る" : "次の設問"}
          </button>
          <button onClick={handleReset} style={{ background: "none", border: "none", color: "#aaa", cursor: "pointer", fontSize: 13 }}>← トップに戻る</button>
        </div>
      )}
    </div>
  );
}

export default App;